code.python:
def min_cost_climbing_stairs(cost):
    a, b = 0, 0
    for i in range(2, len(cost) + 1):
        a, b = b, min(b + cost[i - 1], a + cost[i - 2])
    return b

code.javascript:
function minCostClimbingStairs(cost) {
  let a = 0;
  let b = 0;
  for (let i = 2; i <= cost.length; i++) {
    const next = Math.min(b + cost[i - 1], a + cost[i - 2]);
    a = b;
    b = next;
  }
  return b;
}

